import { test, expect, Page } from '@playwright/test';

test('Amazon.sg Magic Tree House Boxed Set price and add to cart', async ({ browser }) => {
  // 1. Launch browser.
  const context = await browser.newContext();
  const page = await context.newPage();

  // 2. Navigate to https://www.amazon.sg.
  await page.goto('https://www.amazon.sg', { waitUntil: 'domcontentloaded' });

  // 3. Wait for input[name="field-keywords"] to be visible.
  const searchInput = page.locator('input[name="field-keywords"]');
  await expect(searchInput).toBeVisible({ timeout: 15000 });

  // 4. Fill input[name="field-keywords"] with "Magic Tree House Boxed Set".
  await searchInput.fill('Magic Tree House Boxed Set');

  // 5. Press Enter key in input[name="field-keywords"] to submit the search.
  await searchInput.press('Enter');

  // 6. Wait for search results to load and for the first product link to be visible.
  const firstProductLink = page.locator('.s-search-results .s-result-item h2 a').first();
  await expect(firstProductLink).toBeVisible({ timeout: 20000 });

  // 7. Click on the first product link in the search results.
  await firstProductLink.click();

  // 8. Wait for the product detail page to load and for the product title (id="productTitle") to be visible.
  const productTitle = page.locator('#productTitle');
  await expect(productTitle).toBeVisible({ timeout: 15000 });

  // 9. Read the text content of the product title element (id="productTitle").
  const titleText = (await productTitle.textContent())?.trim() || '';

  // 10. Read the text content of the product price element (id="priceblock_ourprice" or id="priceblock_dealprice" or .a-price .a-offscreen).
  let priceText: string | null = null;
  const priceLocators = [
    page.locator('#priceblock_ourprice'),
    page.locator('#priceblock_dealprice'),
    page.locator('.a-price .a-offscreen').first()
  ];
  for (const locator of priceLocators) {
    if (await locator.isVisible({ timeout: 3000 }).catch(() => false)) {
      priceText = (await locator.textContent())?.trim() || null;
      if (priceText) break;
    }
  }

  if (!priceText) {
    throw new Error('Could not find product price on the page.');
  }

  // 11. Parse the price value as a number.
  // Remove currency symbols and commas, handle SGD$ or S$ prefixes
  const priceMatch = priceText.replace(/[^\d.,]/g, '').replace(',', '');
  const priceValue = parseFloat(priceMatch);

  if (isNaN(priceValue)) {
    throw new Error(`Could not parse price value from text: "${priceText}"`);
  }

  // 12. Validate that the price value is less than 25.
  expect(priceValue).toBeLessThan(25);

  // 13. If validation passes, click the "Add to Cart" button (id="add-to-cart-button").
  const addToCartButton = page.locator('#add-to-cart-button');
  await expect(addToCartButton).toBeVisible({ timeout: 10000 });
  await addToCartButton.click();

  // 14. Wait for either a cart confirmation message OR for the cart count element to update and increase by 1.
  // Get initial cart count
  const cartCountLocator = page.locator('#nav-cart-count');
  let initialCartCount = 0;
  if (await cartCountLocator.isVisible({ timeout: 5000 }).catch(() => false)) {
    const cartCountText = (await cartCountLocator.textContent())?.trim() || '0';
    initialCartCount = parseInt(cartCountText, 10) || 0;
  }

  // Wait for confirmation message or cart count to increase
  const confirmationLocator = page.locator('#huc-v2-order-row-confirm-text');
  let confirmationAppeared = false;
  try {
    await Promise.race([
      confirmationLocator.waitFor({ state: 'visible', timeout: 15000 }).then(() => { confirmationAppeared = true; }),
      (async () => {
        for (let i = 0; i < 15; i++) {
          const cartCountText = (await cartCountLocator.textContent())?.trim() || '0';
          const currentCartCount = parseInt(cartCountText, 10) || 0;
          if (currentCartCount > initialCartCount) {
            confirmationAppeared = true;
            break;
          }
          await page.waitForTimeout(1000);
        }
      })()
    ]);
  } catch (e) {
    // ignore timeout here, will check confirmationAppeared below
  }

  expect(confirmationAppeared).toBeTruthy();

  // 15. Close the browser.
  await context.close();
});
